  <text x="20" y="28" fill="#fafafa" font-size="15" font-weight="700" font-family="sans-serif">10 Ekim 2025 — 24 Saatte Yaşananlar</text>
  <text x="20" y="46" fill="#9ca3af" font-size="13" font-family="sans-serif">Kripto türev tarihinin en büyük tasfiye olayı</text>
  <rect x="20" y="70" width="320" height="140" rx="10" fill="#18181b" stroke="#27272a"/>
